from dataclasses import dataclass
from enum import Enum, auto
from functools import wraps
import threading

class Zone(int, Enum):
    REGULATED  = 1
    CONTROLLED = 2
    OPEN       = 3

class Permission(str, Enum):
    READ_REGULATED   = "read:regulated"
    WRITE_REGULATED  = "write:regulated"
    READ_TOKENS      = "read:tokens"
    WRITE_TOKENS     = "write:tokens"
    READ_AUDIT       = "read:audit"
    INVOKE_LLM       = "invoke:llm"
    DEPLOY_MODEL     = "deploy:model"

ROLE_PERMISSIONS: dict[str, set[Permission]] = {
    "data-engineer-regulated": {
        Permission.READ_REGULATED, Permission.WRITE_REGULATED,
        Permission.READ_TOKENS,
    },
    "ai-engineer": {
        Permission.READ_TOKENS, Permission.WRITE_TOKENS,
        Permission.INVOKE_LLM,
    },
    "ml-ops": {Permission.INVOKE_LLM, Permission.DEPLOY_MODEL},
    "audit-reviewer": {Permission.READ_AUDIT},
    "llm-service-account": {Permission.READ_TOKENS, Permission.INVOKE_LLM},
}

_current_principal: threading.local = threading.local()

@dataclass
class Principal:
    user_id: str
    roles: list[str]
    mfa_verified: bool

    @property
    def permissions(self) -> set[Permission]:
        perms: set[Permission] = set()
        for role in self.roles:
            perms |= ROLE_PERMISSIONS.get(role, set())
        return perms

    def has(self, *required: Permission) -> bool:
        return all(p in self.permissions for p in required)

def require_permission(*perms: Permission):
    """Decorator: enforce permission check before any regulated data operation.""""
    def decorator(fn):
        @wraps(fn)
        def wrapper(*args, **kwargs):
            principal: Principal = getattr(_current_principal, "value", None)
            if principal is None:
                raise PermissionError("No authenticated principal in context")
            if not principal.has(*perms):
                raise PermissionError(
                    f"Principal {principal.user_id!r} lacks {[p.value for p in perms]}"
                )
            # Zone 1 operations require hardware-key MFA
            if Permission.READ_REGULATED in perms or Permission.WRITE_REGULATED in perms:
                if not principal.mfa_verified:
                    raise PermissionError("Zone 1 access requires verified MFA")
            return fn(*args, **kwargs)
        return wrapper
    return decorator

# Usage example
class EHRDataService:
    @require_permission(Permission.READ_REGULATED)
    def get_patient_record(self, patient_id: str) -> dict:
        # Actual EHR retrieval — only reachable by data-engineer-regulated role
        return {"patient_id": patient_id, "records": [...]}

    @require_permission(Permission.READ_TOKENS, Permission.INVOKE_LLM)
    def run_clinical_summary(self, token_id: str) -> str:
        # AI engineer path — receives token, not raw PHI
        return f"Summary for token {token_id}"

from dataclasses import dataclass, field

@dataclass
class ChunkMetadata:
    chunk_id: str
    source_doc_id: str
    data_class: str          # "PHI", "POLICY", "SYNTHETIC"
    patient_token: str | None  # None for non-patient documents
    department: str | None
    clearance_level: int     # 1=public, 2=staff, 3=treating_clinician, 4=admin

@dataclass
class RAGQuery:
    query_text: str
    principal: "Principal"
    patient_token: str | None   # If set, restrict to this patient's records

class SecureRAGRetriever:
    def __init__(self, vector_db, chunk_meta_store):
        self._vdb = vector_db
        self._meta = chunk_meta_store

    def retrieve(self, query: RAGQuery, top_k: int = 5) -> list[str]:
        # Step 1: Build a metadata filter from the principal's permissions
        filters = self._build_filters(query)
        # Step 2: Retrieve candidates with metadata filter pre-applied in vector DB
        candidates = self._vdb.similarity_search(
            query.query_text, top_k=top_k * 3, filter=filters
        )
        # Step 3: Post-filter with Python-level RBAC (defence in depth)
        allowed = [
            c for c in candidates
            if self._authorised(query.principal, self._meta.get(c.chunk_id))
        ]
        return [c.text for c in allowed[:top_k]]

    def _build_filters(self, query: RAGQuery) -> dict:
        filters: dict = {}
        if query.patient_token:
            filters["patient_token"] = query.patient_token
        # Only retrieve clearance levels the principal can see
        max_clearance = self._principal_clearance(query.principal)
        filters["clearance_level__lte"] = max_clearance
        return filters

    def _principal_clearance(self, principal: "Principal") -> int:
        if "data-engineer-regulated" in principal.roles:
            return 4
        if "ai-engineer" in principal.roles:
            return 2   # Can see staff-level docs, not patient records directly
        return 1

    def _authorised(self, principal: "Principal", meta: ChunkMetadata | None) -> bool:
        if meta is None:
            return False
        if meta.data_class == "PHI" and meta.patient_token:
            # PHI chunk: principal must have explicit patient-level access
            return "data-engineer-regulated" in principal.roles
        return self._principal_clearance(principal) >= meta.clearance_level

import re
from dataclasses import dataclass

# Patterns for regulated output scanning (combine with NLP classifier for production)
_OUTPUT_PATTERNS = {
    "PAN":  re.compile(r'\b(?:\d[ -]?){12,18}\d\b'),
    "SSN":  re.compile(r'\b\d{3}-\d{2}-\d{4}\b'),
    "PHI_date": re.compile(r'\b(?:born|dob|date of birth)[:\s]+\d{1,2}[/-]\d{1,2}[/-]\d{2,4}\b', re.IGNORECASE),
    "MRN":  re.compile(r'\bMRN[:\s]?\d{6,10}\b', re.IGNORECASE),
}

@dataclass
class EgressScanResult:
    clean: bool
    matches: dict[str, int]   # category → count
    blocked_output: str | None

class EgressDLPGate:
    """
    Placed at the Zone 2 → caller boundary.
    Scans LLM outputs before delivery. Configurable: block or redact.
    """
    def __init__(self, mode: str = "block"):
        assert mode in ("block", "redact")
        self._mode = mode

    def scan(self, text: str) -> EgressScanResult:
        matches: dict[str, int] = {}
        for category, pattern in _OUTPUT_PATTERNS.items():
            found = pattern.findall(text)
            if found:
                matches[category] = len(found)

        if not matches:
            return EgressScanResult(clean=True, matches={}, blocked_output=None)

        if self._mode == "block":
            return EgressScanResult(clean=False, matches=matches, blocked_output=None)

        # Redact mode: mask matches
        redacted = text
        for category, pattern in _OUTPUT_PATTERNS.items():
            redacted = pattern.sub(f"[REDACTED-{category}]", redacted)
        return EgressScanResult(clean=False, matches=matches, blocked_output=redacted)
